// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

const getConditionEmoji = (condition: string = '') => {
  const lowerCond = condition.toLowerCase();
  if (lowerCond.includes('sun') || lowerCond.includes('clear')) return '☀️';
  if (lowerCond.includes('partly')) return '⛅';
  if (lowerCond.includes('cloud')) return '☁️';
  if (lowerCond.includes('rain') || lowerCond.includes('shower') || lowerCond.includes('drizzle')) return '🌧️';
  if (lowerCond.includes('storm') || lowerCond.includes('thunder')) return '⛈️';
  if (lowerCond.includes('snow') || lowerCond.includes('flurries')) return '❄️';
  if (lowerCond.includes('wind')) return '💨';
  if (lowerCond.includes('fog') || lowerCond.includes('mist')) return '🌫️';
  return '🌡️';
};

function useComponent(props: Props) {
  const currentEmoji = useMemo(() => getConditionEmoji(props.condition), [props.condition]);
  return { currentEmoji };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="sm">
      <Card padding={24} shadow="md" radius="xl">
        <Stack gap={24}>
          {/* Header */}
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={3}>{props.city}</Heading>
            <Badge variant="primary" size="lg" pill>{props.condition}</Badge>
          </Stack>

          {/* Current Weather & Details */}
          <Stack direction="horizontal" justify="between" align="center" wrap>
            <Stack direction="horizontal" align="center" gap={16}>
              <span style={{ fontSize: '56px', lineHeight: 1 }}>{state.currentEmoji}</span>
              <Text size="4xl" weight="bold">
                {props.temperature}°{props.unit}
              </Text>
            </Stack>

            <Stack gap={12}>
              <Stack direction="horizontal" align="center" gap={8}>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">💧 Humidity:</Text>
                <Text variant="bodySmall" weight="semibold">{props.humidity}%</Text>
              </Stack>
              <Stack direction="horizontal" align="center" gap={8}>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">💨 Wind:</Text>
                <Text variant="bodySmall" weight="semibold">{props.windSpeed} {props.unit === 'F' ? 'mph' : 'km/h'}</Text>
              </Stack>
            </Stack>
          </Stack>

          <Divider margin={0} />

          {/* Forecast */}
          <Stack direction="horizontal" justify="between" wrap>
            {props.forecast.map((dayData, i) => (
              <Stack key={i} align="center" gap={8}>
                <Text variant="bodySmall" weight="medium" color="var(--ggui-color-onSurfaceVariant)">
                  {dayData.day || 'Day'}
                </Text>
                <span style={{ fontSize: '28px', lineHeight: 1 }}>
                  {getConditionEmoji(dayData.icon || '')}
                </span>
                <Stack direction="horizontal" gap={6} align="center">
                  <Text variant="bodySmall" weight="bold">{dayData.high ?? '--'}°</Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{dayData.low ?? '--'}°</Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

const COLORS = [
  { bg: 'var(--ggui-color-primary-100, #e0f2fe)', fg: 'var(--ggui-color-primary-800, #075985)' },
  { bg: 'var(--ggui-color-success-100, #dcfce7)', fg: 'var(--ggui-color-success-800, #166534)' },
  { bg: 'var(--ggui-color-warning-100, #fef3c7)', fg: 'var(--ggui-color-warning-800, #92400e)' },
  { bg: 'var(--ggui-color-error-100, #fee2e2)', fg: 'var(--ggui-color-error-800, #991b1b)' },
  { bg: 'var(--ggui-color-info-100, #cffafe)', fg: 'var(--ggui-color-info-800, #155e75)' },
  { bg: 'var(--ggui-color-primary-200, #bae6fd)', fg: 'var(--ggui-color-primary-900, #0c4a6e)' },
  { bg: 'var(--ggui-color-success-200, #bbf7d0)', fg: 'var(--ggui-color-success-900, #14532d)' },
  { bg: 'var(--ggui-color-warning-200, #fde68a)', fg: 'var(--ggui-color-warning-900, #78350f)' },
  { bg: 'var(--ggui-color-error-200, #fecaca)', fg: 'var(--ggui-color-error-900, #7f1d1d)' },
  { bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)', fg: 'var(--ggui-color-onSurfaceVariant, #52525b)' },
  { bg: 'var(--ggui-color-info-200, #a5f3fc)', fg: 'var(--ggui-color-info-900, #164e63)' },
  { bg: 'var(--ggui-color-primary-50, #f0f9ff)', fg: 'var(--ggui-color-primary-700, #0369a1)' },
];

function useComponent(props: Props) {
  const [search, setSearch] = useState('');
  const [selectedElement, setSelectedElement] = useState<any>(null);

  const categories = useMemo(() => {
    const cats = Array.from(new Set((props.elements || []).map(e => e.category).filter(Boolean))) as string[];
    cats.sort();
    return cats;
  }, [props.elements]);

  const categoryColors = useMemo(() => {
    const map: Record<string, { bg: string, fg: string }> = {};
    categories.forEach((cat, idx) => {
      map[cat] = COLORS[idx % COLORS.length];
    });
    return map;
  }, [categories]);

  const elementsWithMatch = useMemo(() => {
    const q = search.toLowerCase();
    return (props.elements || []).map(e => {
      const matches = !q || ((e.name?.toLowerCase().includes(q)) || (e.symbol?.toLowerCase().includes(q)));
      return { ...e, matches };
    });
  }, [props.elements, search]);

  return {
    search,
    setSearch,
    selectedElement,
    setSelectedElement,
    categories,
    categoryColors,
    elementsWithMatch
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={32}>
        <Stack gap={8}>
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
            Explore the properties of chemical elements. Use the search to filter, or select an element for details.
          </Text>
        </Stack>

        <div style={{ width: '100%', overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-6, 24px)' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(18, minmax(64px, 1fr))', gap: 'var(--ggui-spacing-2, 8px)', minWidth: '1152px' }}>

            <div style={{ gridColumn: '3 / 11', gridRow: '1 / 4', padding: '0 var(--ggui-spacing-4, 16px)', display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-4, 16px)', zIndex: 10 }}>
              <SearchField 
                value={state.search} 
                onChange={state.setSearch} 
                placeholder="Search elements by name or symbol..." 
              />

              {state.selectedElement ? (
                <Card padding={16} shadow="sm" border>
                  <Stack direction="horizontal" gap={20} align="center">
                    <Box background={state.categoryColors[state.selectedElement.category || '']?.bg || COLORS[0].bg} borderRadius={8} style={{ width: 80, height: 80, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                      <Stack gap={4} align="center">
                        <Text size="sm" weight="semibold" color={state.categoryColors[state.selectedElement.category || '']?.fg || COLORS[0].fg}>{state.selectedElement.atomicNumber}</Text>
                        <Heading level={2} color={state.categoryColors[state.selectedElement.category || '']?.fg || COLORS[0].fg} style={{ margin: 0, lineHeight: 1 }}>{state.selectedElement.symbol}</Heading>
                      </Stack>
                    </Box>
                    <Stack gap={4}>
                      <Heading level={3} style={{ margin: 0 }}>{state.selectedElement.name}</Heading>
                      <Text size="sm" color="var(--ggui-color-onSurfaceVariant)">
                        <strong>Weight:</strong> {state.selectedElement.atomicWeight}
                      </Text>
                      <Text size="sm" color="var(--ggui-color-onSurfaceVariant)">
                        <strong>Category:</strong> <span style={{ textTransform: 'capitalize' }}>{state.selectedElement.category}</span>
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              ) : (
                <Card padding={16} shadow="none" border>
                  <div style={{ height: '80px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                    <Text color="var(--ggui-color-onSurfaceVariant)">Select an element to view details</Text>
                  </div>
                </Card>
              )}
            </div>

            {state.elementsWithMatch.map(el => {
              if (!el.row || !el.col) return null;
              const color = state.categoryColors[el.category || ''] || COLORS[0];
              const isSelected = state.selectedElement?.atomicNumber === el.atomicNumber;

              return (
                <div key={el.atomicNumber} style={{ gridColumn: el.col, gridRow: el.row }}>
                  <Box as={Clickable} 
                    onClick={() => state.setSelectedElement(el)}
                    background={color.bg}
                    borderRadius={6}
                    padding={0}
                    style={{
                      position: 'relative',
                      opacity: el.matches ? 1 : 0.15,
                      height: '100%',
                      minHeight: '64px',
                      display: 'flex',
                      flexDirection: 'column',
                      justifyContent: 'center',
                      border: isSelected ? '2px solid var(--ggui-color-onSurface, #18181b)' : '2px solid transparent',
                      boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
                      transition: 'all 0.2s ease-in-out',
                      cursor: 'pointer'
                    }}
                    hoverStyle={{ opacity: el.matches ? 0.8 : 0.4 }}
                  >
                    <div style={{ position: 'absolute', top: 4, left: 6 }}>
                      <Text size="xs" color={color.fg} style={{ fontSize: '10px', lineHeight: 1, fontWeight: 600 }}>{el.atomicNumber}</Text>
                    </div>
                    <Text size="lg" weight="bold" align="center" color={color.fg} style={{ lineHeight: 1, marginTop: 'var(--ggui-spacing-2, 8px)' }}>{el.symbol}</Text>
                  </Box>
                </div>
              );
            })}
          </div>
        </div>

        <Divider margin={0} />

        <Stack gap={16}>
          <Heading level={4}>Categories</Heading>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 'var(--ggui-spacing-4, 16px)' }}>
            {state.categories.map(cat => (
              <div key={cat} style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2, 8px)' }}>
                <div style={{ 
                  width: 16, 
                  height: 16, 
                  borderRadius: 4, 
                  background: state.categoryColors[cat]?.bg, 
                  border: `1px solid ${state.categoryColors[cat]?.fg}` 
                }} />
                <Text size="sm" style={{ textTransform: 'capitalize' }}>{cat}</Text>
              </div>
            ))}
          </div>
        </Stack>

      </Stack>
    </Container>
  );
}

