import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
  onAddToCart?: (data: Record<string, unknown>) => void; // Action: Add to Cart
}

function StarRating({ rating }: { rating: number }) {
  return (
    <div 
      style={{ display: 'flex', gap: 'var(--ggui-spacing-1, 4px)' }}
      role="img"
      aria-label={`Rating: ${rating} out of 5 stars`}
    >
      {[1, 2, 3, 4, 5].map(i => (
        <Icon key={i} size={16} color={i <= rating ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outlineVariant, #e4e4e7)'}>
          <svg viewBox="0 0 24 24" fill={i <= rating ? "currentColor" : "none"} stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2" />
          </svg>
        </Icon>
      ))}
    </div>
  );
}

function useComponent(props: Props) {
  const handleAddToCart = useCallback((data: Record<string, unknown>) => {
    props.onAddToCart?.(data);
  }, [props.onAddToCart]);

  const stock = props.product?.stock ?? 0;
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const decrement = useCallback(() => setQuantity(q => Math.max(1, q - 1)), []);
  const increment = useCallback(() => setQuantity(q => Math.min(stock, q + 1)), [stock]);

  const onAdd = useCallback(() => {
    handleAddToCart({ productId: props.product?.id, quantity });
  }, [handleAddToCart, props.product?.id, quantity]);

  const formattedPrice = useMemo(() => {
    return new Intl.NumberFormat(undefined, { 
      style: 'currency', 
      currency: props.product?.currency || 'USD' 
    }).format(props.product?.price ?? 0);
  }, [props.product?.price, props.product?.currency]);

  return {
    product: props.product || {},
    stock,
    quantity,
    activeTab,
    setActiveTab,
    decrement,
    increment,
    onAdd,
    formattedPrice
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={32}>
        {/* Top Section */}
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 'var(--ggui-spacing-8, 32px)' }}>
          {/* Image Area */}
          <div style={{ flex: '1 1 300px', minWidth: '300px' }}>
            <div style={{
              width: '100%',
              aspectRatio: '1 / 1',
              backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
              borderRadius: 'var(--ggui-shape-radius-xl, 16px)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              border: '1px solid var(--ggui-color-primary-100, #e0f2fe)',
              padding: 'var(--ggui-spacing-6, 24px)',
              textAlign: 'center'
            }}>
              <Text size="xl" weight="semibold" color="var(--ggui-color-primary-500, #0ea5e9)">
                {state.product.name || 'Product Image'}
              </Text>
            </div>
          </div>

          {/* Details Area */}
          <div style={{ flex: '2 1 400px', minWidth: '300px' }}>
            <Stack gap={24}>
              <Stack gap={12}>
                <Heading level={1}>{state.product.name || 'Unknown Product'}</Heading>

                <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2, 8px)' }}>
                  <StarRating rating={state.product.rating ?? 0} />
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    ({state.product.reviewCount ?? 0} reviews)
                  </Text>
                </div>
              </Stack>

              <Heading level={2} color="var(--ggui-color-primary-700, #0369a1)">
                {state.formattedPrice}
              </Heading>

              <div>
                {state.stock > 10 ? (
                  <Badge variant="success">In Stock</Badge>
                ) : state.stock > 0 ? (
                  <Badge variant="warning">Low Stock</Badge>
                ) : (
                  <Badge variant="error">Out of Stock</Badge>
                )}
              </div>
            </Stack>
          </div>
        </div>

        {/* Tabs Section */}
        <Card padding={0} shadow="sm">
          <Tabs
            variant="line"
            activeKey={state.activeTab}
            onChange={state.setActiveTab}
            items={[
              {
                key: 'description',
                label: 'Description',
                content: (
                  <Box paddingX={24} paddingY={16}>
                    <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                      {state.product.description || 'No description available.'}
                    </Text>
                  </Box>
                )
              },
              {
                key: 'specifications',
                label: 'Specifications',
                content: (
                  <Box paddingX={24} paddingY={16}>
                    <Table
                      columns={[{ key: 'label', header: 'Specification', width: '30%' }, { key: 'value', header: 'Value' }]}
                      data={(state.product.specifications || []) as any[]}
                      bordered
                      striped
                    />
                  </Box>
                )
              },
              {
                key: 'reviews',
                label: 'Reviews',
                content: (
                  <Box paddingX={24} paddingY={16}>
                    <Stack gap={16}>
                      {(!state.product.reviews || state.product.reviews.length === 0) ? (
                        <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">No reviews yet.</Text>
                      ) : (
                        (state.product.reviews as any[]).map((r, i) => (
                          <Card key={i} padding={16} shadow="none" border>
                            <Stack gap={8}>
                              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2, 8px)' }}>
                                  <Avatar name={r.author} size="sm" />
                                  <Text variant="label">{r.author}</Text>
                                </div>
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                  {r.date}
                                </Text>
                              </div>
                              <StarRating rating={r.rating ?? 0} />
                              <Text>{r.text}</Text>
                            </Stack>
                          </Card>
                        ))
                      )}
                    </Stack>
                  </Box>
                )
              }
            ]}
          />
        </Card>

        {/* Bottom Section */}
        <Card padding={24} shadow="sm">
          <Stack direction="horizontal" align="center" justify="between" wrap>
            <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-4, 16px)' }}>
              <Text variant="label">Quantity</Text>
              <div style={{ display: 'flex', alignItems: 'center', border: '1px solid var(--ggui-color-outline, #d4d4d8)', borderRadius: 'var(--ggui-shape-radius-md, 8px)', padding: '2px' }}>
                <Button aria-label="Decrease quantity" variant="ghost" size="sm" onClick={state.decrement} disabled={state.quantity <= 1 || state.stock === 0}>
                  <Icon name="minus" size={16} />
                </Button>
                <div style={{ width: '40px', textAlign: 'center' }}>
                  <Text weight="medium">{state.quantity}</Text>
                </div>
                <Button aria-label="Increase quantity" variant="ghost" size="sm" onClick={state.increment} disabled={state.quantity >= state.stock || state.stock === 0}>
                  <Icon name="plus" size={16} />
                </Button>
              </div>
            </div>
            <Button 
              variant="primary" 
              size="lg" 
              onClick={state.onAdd} 
              disabled={state.stock === 0} 
              leftIcon={
                <Icon size={18}>
                  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <circle cx="9" cy="21" r="1" />
                    <circle cx="20" cy="21" r="1" />
                    <path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6" />
                  </svg>
                </Icon>
              }
            >
              Add to Cart
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

