import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (data: Record<string, unknown>) => void;
}

function useComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState(props.initialProfile?.email ?? '');

  const avatarOpts = props.avatarOptions || [];
  const [avatar, setAvatar] = useState(props.initialProfile?.avatar ?? avatarOpts[0] ?? '');

  const roleOpts = props.roleOptions || [];
  const [role, setRole] = useState(props.initialProfile?.role ?? roleOpts[0] ?? '');

  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile?.theme ?? 'light');

  const handleComplete = useCallback(() => {
    props.onComplete?.({ name, email, avatar, role, emailNotifications, theme });
  }, [props.onComplete, name, email, avatar, role, emailNotifications, theme]);

  const isValidEmail = useMemo(() => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }, [email]);

  const isStep1Valid = useMemo(() => {
    return name.trim().length > 0 && isValidEmail && avatar.length > 0;
  }, [name, isValidEmail, avatar]);

  const isStep2Valid = useMemo(() => {
    return role.length > 0;
  }, [role]);

  const nextStep = useCallback(() => {
    if (step === 1 && isStep1Valid) {
      setStep(2);
    } else if (step === 2 && isStep2Valid) {
      setStep(3);
    }
  }, [step, isStep1Valid, isStep2Valid]);

  const prevStep = useCallback(() => {
    if (step > 1) {
      setStep(step - 1);
    }
  }, [step]);

  return {
    step, nextStep, prevStep,
    name, setName,
    email, setEmail,
    avatar, setAvatar,
    role, setRole,
    emailNotifications, setEmailNotifications,
    theme, setTheme,
    isStep1Valid,
    isStep2Valid,
    handleComplete,
    avatarOptions: avatarOpts,
    roleOptions: roleOpts
  };
}

