function useComponent(props: Props) {
  const handleTaskUpdate = useCallback((data: Record<string, unknown>) => {
    props.onTaskUpdate?.(data);
  }, [props.onTaskUpdate]);

  const [tasks, setTasks] = useState(props.tasks || []);
  const [isAdding, setIsAdding] = useState<Record<string, any>>({});

  const columns = props.columns || [{id: 'todo', name: 'To Do'}, {id: 'in-progress', name: 'In Progress'}, {id: 'done', name: 'Done'}];

  const stats = useMemo(() => ({
    total: tasks.length,
    completed: tasks.filter(t => t.column === 'done').length
  }), [tasks]);

  const updateTask = useCallback((id: string, updates: any) => {
    const nextTasks = tasks.map(t => t.id === id ? { ...t, ...updates } : t);
    setTasks(nextTasks);
    handleTaskUpdate({ type: 'UPDATE_TASK', task: { id, ...updates } });
  }, [tasks, handleTaskUpdate]);

  const addTask = useCallback((columnId: string, title: string, priority: 'low' | 'medium' | 'high') => {
    const newTask = { id: Math.random().toString(36).substr(2, 9), title, priority, column: columnId, assignee: '??' };
