    setIsAdding(prev => ({ ...prev, [columnId]: false, [columnId + '_title']: '', [columnId + '_priority']: 'medium' }));
    handleTaskUpdate({ type: 'ADD_TASK', task: newTask });
  }, [tasks, handleTaskUpdate]);

  return { tasks, columns, stats, updateTask, addTask, isAdding, setIsAdding };
}

