        <Stack gap={16} style={{ flex: '1 1 300px', justifyContent: 'center' }}>
          <Heading level={1}>{name}</Heading>
          <Heading level={3} color="var(--ggui-color-primary-600)">{currency}{price}</Heading>
          <Row align="center" gap={8}>
            <Row gap={2} aria-label={`Rating: ${rating} out of 5 stars`}>
              {[1, 2, 3, 4, 5].map((star) => (
                <Icon key={star} size={20} color={star <= Math.round(rating || 0) ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}>
                  <svg viewBox="0 0 24 24" fill="currentColor"><path d="M12 17.27L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2 9.19 8.63 2 9.24l5.46 4.73L5.82 21z"/></svg>
                </Icon>
              ))}
            </Row>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">({props.product.reviewCount || 0} reviews)</Text>
          </Row>
          <Box>
            <Badge variant={stock === 0 ? 'error' : stock < 5 ? 'warning' : 'success'} size="md">
              {stock === 0 ? 'Out of Stock' : stock < 5 ? `Low Stock (${stock} left)` : 'In Stock'}
            </Badge>
          </Box>
        </Stack>
      </Row>

      <Spacer size={64} />

      <Tabs
        variant="line"
        items={[
          { key: 'description', label: 'Description', content: <Box paddingY={16}><Text variant="body">{description}</Text></Box> },
          { key: 'specifications', label: 'Specifications', content: <Table data={specifications as any[]} columns={[{key: 'key', header: 'Key'}, {key: 'value', header: 'Value'}]} /> },
          { key: 'reviews', label: 'Reviews', content: <Stack gap={16}>{(reviews as any[])?.map((r, i) => <Card key={i} padding={16}><Stack gap={4}><Text variant="label">{r.author}</Text><Text variant="caption">{r.date}</Text><Text>{r.text}</Text></Stack></Card>)}</Stack> }
        ]}
        activeKey={activeTab}
        onChange={setActiveTab}
      />

      <Spacer size={48} />
      <Divider />
      <Spacer size={32} />

      <Stack direction="horizontal" gap={12} align="center" justify="start">
        <Text variant="label">Quantity:</Text>
        <Button onClick={decrement} variant="secondary" aria-label="Decrease quantity" disabled={quantity <= 1 || isOutOfStock}><Icon name="minus" size={16} /></Button>
        <Text variant="body" style={{ minWidth: 40, textAlign: 'center', fontWeight: 'bold' }}>{quantity}</Text>
        <Button onClick={increment} variant="secondary" aria-label="Increase quantity" disabled={quantity >= (stock || 0) || isOutOfStock}><Icon name="plus" size={16} /></Button>
        <Spacer size={16} />
        <Button onClick={addToCart} size="lg" variant="primary" disabled={isOutOfStock} style={{ minWidth: 240 }}>
          Add to Cart
        </Button>
      </Stack>
    </Container>
  );
}

// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
  onComplete?: (data: Record<string, unknown>) => void; // Action: Complete Setup
}

function useComponent(props: Props) {
  const handleComplete = useCallback((data: Record<string, unknown>) => {
    props.onComplete?.(data);
  }, [props.onComplete]);

  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name || '',
    email: props.initialProfile?.email || '',
    avatar: props.initialProfile?.avatar || props.avatarOptions[0],
    role: props.initialProfile?.role || '',
    emailNotifications: !!props.initialProfile?.emailNotifications,
    theme: props.initialProfile?.theme || 'light',
  });

  const errors = useMemo(() => {
    const errs: Record<string, string> = {};
    if (!formData.name.trim()) errs.name = 'Name is required';
    if (formData.email.trim() && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) errs.email = 'Invalid email format';
    else if (!formData.email.trim()) errs.email = 'Email is required';
    return errs;
  }, [formData.name, formData.email]);

  const isStepValid = useMemo(() => {
    if (currentStep === 1) return formData.name.trim() !== '' && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email);
    if (currentStep === 2) return !!formData.role && formData.role !== '';
    return true;
  }, [currentStep, errors, formData.role]);

  const nextStep = () => setCurrentStep((s) => Math.min(s + 1, 3));
  const prevStep = () => setCurrentStep((s) => Math.max(s - 1, 1));

  return { currentStep, formData, setFormData, errors, isStepValid, nextStep, prevStep, handleComplete };
}

export default function Component(props: Props) {
  const { currentStep, formData, setFormData, errors, isStepValid, nextStep, prevStep, handleComplete } = useComponent(props);

  return (
    <Container maxWidth="sm" padding={24}>
      <Stack gap={24}>
        <Stack gap={8}>
          <Heading level={2}>Step {currentStep} of 3</Heading>
          <Progress value={(currentStep / 3) * 100} size="md" />
        </Stack>

        <Card padding={24}>
          {currentStep === 1 && (
            <Stack gap={16}>
              <FormField label="Name" required error={errors.name}><Input value={formData.name} onChange={(v) => setFormData({ ...formData, name: v })} /></FormField>
              <FormField label="Email" required error={errors.email}><Input value={formData.email} onChange={(v) => setFormData({ ...formData, email: v })} /></FormField>
              <Text variant="label">Avatar</Text>
              <Row gap={8}>{props.avatarOptions.map((opt) => <Button key={opt} variant={formData.avatar === opt ? 'primary' : 'ghost'} onClick={() => setFormData({ ...formData, avatar: opt })}>{opt}</Button>)}</Row>
            </Stack>
          )}

          {currentStep === 2 && (
            <Stack gap={16}>
              <FormField label="Role"><Select value={formData.role} onChange={(v) => setFormData({ ...formData, role: v })} options={props.roleOptions.map((r) => ({ value: r, label: r }))} placeholder="Select a role" /></FormField>
              <Toggle label="Email Notifications" checked={formData.emailNotifications} onChange={(v) => setFormData({ ...formData, emailNotifications: v })} />
              <Toggle label="Dark Theme" checked={formData.theme === 'dark'} onChange={(v) => setFormData({ ...formData, theme: v ? 'dark' : 'light' })} />
            </Stack>
          )}

          {currentStep === 3 && (
            <Stack gap={12}>
              <Heading level={4}>Review</Heading>
              <Text>Name: {formData.name}</Text>
              <Text>Email: {formData.email}</Text>
              <Text>Role: {formData.role}</Text>
            </Stack>
          )}
        </Card>

        <Row gap={16} justify="between">
          <Button variant="outline" disabled={currentStep === 1} onClick={prevStep}>Back</Button>
          {currentStep < 3 ? (
            <Button variant="primary" disabled={!isStepValid} onClick={nextStep}>Next</Button>
          ) : (
            <Button variant="primary" onClick={() => handleComplete(formData)}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
